export const INSTALL_SH = "#!/bin/sh\n# Myra Agents — remote instance installer (macOS + Linux).\n#\n#   curl -sSf https://<host>/install-remote.sh | MYRA_HUB_URL=<hub> CODE=<code> sh\n#\n# Downloads the right myra-server binary from GitHub Releases, verifies its\n# checksum, enrolls (if CODE is set), and installs a per-user service. Idempotent\n# — re-run to update the binary.\nset -eu\n\nREPO=\"${MYRA_REPO:-Gamma-Software/Myra-Agents}\"\nBASE=\"https://github.com/${REPO}/releases/${MYRA_RELEASE:-latest/download}\"\n\nsay() { printf '\\033[36m[install]\\033[0m %s\\n' \"$1\"; }\ndie() { printf '\\033[31m[install] %s\\033[0m\\n' \"$1\" >&2; exit 1; }\n\n# 1. Detect OS + arch → release asset name.\nos=\"$(uname -s)\"\narch=\"$(uname -m)\"\ncase \"$os\" in\n  Linux)  plat=\"unknown-linux-gnu\" ;;\n  Darwin) plat=\"apple-darwin\" ;;\n  *) die \"unsupported OS: $os\" ;;\nesac\ncase \"$arch\" in\n  x86_64|amd64) cpu=\"x86_64\" ;;\n  aarch64|arm64) cpu=\"aarch64\" ;;\n  *) die \"unsupported arch: $arch\" ;;\nesac\nasset=\"myra-server-${cpu}-${plat}\"\nurl=\"${BASE}/${asset}\"\n\n# 2. Pick install dir.\nif [ \"$os\" = \"Darwin\" ] && [ -w /usr/local/bin ] 2>/dev/null; then\n  bindir=\"/usr/local/bin\"\nelse\n  bindir=\"${HOME}/.local/bin\"\nfi\nmkdir -p \"$bindir\"\ndest=\"${bindir}/myra-server\"\n\nfetch() { curl -fsSL \"$1\" -o \"$2\" || die \"download failed: $1\"; }\n\nsay \"downloading ${asset}\"\ntmp=\"$(mktemp)\"\nfetch \"$url\" \"$tmp\"\n\n# Verify checksum (best-effort: skip if the .sha256 asset is missing).\nif curl -fsSL \"${url}.sha256\" -o \"${tmp}.sha256\" 2>/dev/null; then\n  expected=\"$(cut -d' ' -f1 < \"${tmp}.sha256\")\"\n  if command -v sha256sum >/dev/null 2>&1; then\n    actual=\"$(sha256sum \"$tmp\" | cut -d' ' -f1)\"\n  else\n    actual=\"$(shasum -a 256 \"$tmp\" | cut -d' ' -f1)\"\n  fi\n  [ \"$expected\" = \"$actual\" ] || die \"checksum mismatch (expected $expected, got $actual)\"\n  say \"checksum ok\"\nelse\n  say \"no checksum published — skipping verification\"\nfi\n\nmv \"$tmp\" \"$dest\"\nchmod +x \"$dest\"\n\n# 3. macOS: clear the Gatekeeper quarantine flag on the downloaded binary.\nif [ \"$os\" = \"Darwin\" ]; then\n  xattr -d com.apple.quarantine \"$dest\" 2>/dev/null || true\nfi\nsay \"installed → $dest\"\n\ncase \":$PATH:\" in\n  *\":$bindir:\"*) ;;\n  *) say \"note: $bindir is not on your PATH — add it to use 'myra-server' directly\" ;;\nesac\n\n# 4. Enroll if a pairing code was provided.\nif [ -n \"${CODE:-}\" ]; then\n  [ -n \"${MYRA_HUB_URL:-}\" ] || die \"CODE set but MYRA_HUB_URL is not\"\n  say \"enrolling…\"\n  \"$dest\" enroll \"$CODE\"\n  # 5. Install the per-user service so it survives logout/reboot.\n  say \"installing service…\"\n  \"$dest\" install-service\nelse\n  say \"no CODE — skipping enroll. Pair later with: myra-server enroll <code>\"\nfi\n\nsay \"done\"\n";

export const INSTALL_PS1 = "# Myra Agents — remote instance installer (Windows).\n#\n#   $env:MYRA_HUB_URL=\"<hub>\"; $env:CODE=\"<code>\"; iwr https://<host>/install-remote.ps1 | iex\n#\n# Downloads the myra-server binary from GitHub Releases, verifies its checksum,\n# enrolls (if CODE is set), and registers a per-user ONLOGON task. Idempotent.\n$ErrorActionPreference = \"Stop\"\n\n$repo = if ($env:MYRA_REPO) { $env:MYRA_REPO } else { \"Gamma-Software/Myra-Agents\" }\n$rel  = if ($env:MYRA_RELEASE) { $env:MYRA_RELEASE } else { \"latest/download\" }\n$base = \"https://github.com/$repo/releases/$rel\"\n\nfunction Say($m) { Write-Host \"[install] $m\" -ForegroundColor Cyan }\n\n$asset = \"myra-server-x86_64-pc-windows-msvc.exe\"\n$url   = \"$base/$asset\"\n\n$bindir = Join-Path $HOME \".myra-agents\\bin\"\nNew-Item -ItemType Directory -Force -Path $bindir | Out-Null\n$dest = Join-Path $bindir \"myra-server.exe\"\n\nSay \"downloading $asset\"\n$tmp = [System.IO.Path]::GetTempFileName()\nInvoke-WebRequest -Uri $url -OutFile $tmp\n\n# Verify checksum (best-effort).\ntry {\n  $sumFile = \"$tmp.sha256\"\n  Invoke-WebRequest -Uri \"$url.sha256\" -OutFile $sumFile -ErrorAction Stop\n  $expected = (Get-Content $sumFile -Raw).Trim().Split(\" \")[0]\n  $actual = (Get-FileHash $tmp -Algorithm SHA256).Hash.ToLower()\n  if ($expected.ToLower() -ne $actual) { throw \"checksum mismatch (expected $expected, got $actual)\" }\n  Say \"checksum ok\"\n} catch {\n  Say \"no checksum published or verification skipped\"\n}\n\nMove-Item -Force $tmp $dest\nSay \"installed -> $dest\"\n\n# Add bindir to the user PATH if missing.\n$userPath = [Environment]::GetEnvironmentVariable(\"Path\", \"User\")\nif ($userPath -notlike \"*$bindir*\") {\n  [Environment]::SetEnvironmentVariable(\"Path\", \"$userPath;$bindir\", \"User\")\n  $env:Path = \"$env:Path;$bindir\"\n  Say \"added $bindir to user PATH (restart shells to pick it up)\"\n}\n\n# Enroll + install service if a pairing code was provided.\nif ($env:CODE) {\n  if (-not $env:MYRA_HUB_URL) { throw \"CODE set but MYRA_HUB_URL is not\" }\n  Say \"enrolling...\"\n  & $dest enroll $env:CODE\n  Say \"installing service...\"\n  & $dest install-service\n} else {\n  Say \"no CODE - skipping enroll. Pair later with: myra-server enroll <code>\"\n}\n\nSay \"done\"\n";
